const b      = $json.body;
const lang   = b.targetLanguage || 'Spanish';
const brand  = b.brandName      || 'Brand';
const text   = b.campaignText   || 'Special Offer';
const jobId  = `LOC-${Date.now()}`;

const prompt = `Recreate this marketing image with all embedded text accurately translated into ${lang}. ` +
  `Preserve the exact original layout, visual hierarchy, font style and brand colours. ` +
  `Brand: ${brand}. Translated headline in ${lang}: "${text}". ` +
  `Photorealistic quality, sharp typography, professional marketing aesthetic, 1024x1024.`;

return [{ json: { prompt, lang, brand, campaignText: text, jobId,
                  masterImageUrl: b.masterImageUrl || '' } }];

const pred  = $json.predictions?.[0];
if (!pred) throw new Error('Imagen 3 returned no prediction');
const b64   = pred.bytesBase64Encoded;
const mime  = pred.mimeType || 'image/png';
const ext   = mime.split('/')[1] || 'png';
const prev  = $('Build Localize Prompt').item.json;
const fname = `localized_${prev.lang.toLowerCase().replace(/\s+/g,'_')}_${prev.jobId}.${ext}`;
const buf   = Buffer.from(b64, 'base64');
return [{
  json:   { ...prev, filename: fname, mimeType: mime },
  binary: { data: { data: b64, mimeType: mime, fileName: fname,
                    fileSize: buf.length, fileExtension: ext } }
}];

const p = $('Build Localize Prompt').item.json;
return [{ json: {
  success: true, jobId: p.jobId, jobType: 'localize',
  language: p.lang, brand: p.brand,
  filename: p.filename,
  publicUrl: `https://YOUR_CDN_DOMAIN/${p.filename}`,
  generatedAt: new Date().toISOString()
}}];

const b       = $json.body;
const product = b.productType      || 't-shirt';
const colors  = b.colorScheme      || 'navy and gold';
const logo    = b.logoDescription  || 'brand logo';
const jobId   = `MKP-${Date.now()}`;

const prompt = `Photorealistic product mockup of a ${product}. ` +
  `Apply a ${logo} using ${colors} colour scheme. ` +
  `Studio background, professional lighting, natural fabric texture, realistic shadows and highlights. ` +
  `Premium commercial product photo ready for e-commerce. 1024x1024, no text overlays.`;

return [{ json: { prompt, product, colors, logo, jobId } }];

const pred  = $json.predictions?.[0];
if (!pred) throw new Error('Imagen 3 returned no prediction');
const b64   = pred.bytesBase64Encoded;
const mime  = pred.mimeType || 'image/png';
const ext   = mime.split('/')[1] || 'png';
const prev  = $('Build Mockup Prompt').item.json;
const fname = `mockup_${prev.product.replace(/\s+/g,'_')}_${prev.jobId}.${ext}`;
const buf   = Buffer.from(b64, 'base64');
return [{
  json:   { ...prev, filename: fname, mimeType: mime },
  binary: { data: { data: b64, mimeType: mime, fileName: fname,
                    fileSize: buf.length, fileExtension: ext } }
}];

const p = $('Build Mockup Prompt').item.json;
return [{ json: {
  success: true, jobId: p.jobId, jobType: 'mockup',
  productType: p.product, colorScheme: p.colors,
  filename: p.filename,
  publicUrl: `https://YOUR_CDN_DOMAIN/${p.filename}`,
  generatedAt: new Date().toISOString()
}}];
